const checkpoints = [];

const searchParams = JSON.parse(localStorage.getItem('task1_searchParams') || 'null');
const shows = JSON.parse(localStorage.getItem('shows') || '[]');
const showPackages = JSON.parse(localStorage.getItem('show_packages') || '[]');
const bookings = JSON.parse(localStorage.getItem('bookings') || '[]');
const metadata = JSON.parse(localStorage.getItem('_metadata') || 'null');
const baselineStr = metadata && metadata.baselineDate ? metadata.baselineDate : null;

function isNextMonth(dateStr, baselineStr) {
  if (!dateStr || !baselineStr) return false;
  const base = new Date(baselineStr + 'T00:00:00Z');
  const d = new Date(dateStr + 'T00:00:00Z');
  let nextMonth = base.getUTCMonth() + 1;
  let nextYear = base.getUTCFullYear();
  if (nextMonth > 11) { nextMonth = 0; nextYear += 1; }
  return d.getUTCFullYear() === nextYear && d.getUTCMonth() === nextMonth;
}

// CP1 (0.5): User searched kids parties in Chicago with correct filters (event type, rating, price, duration, guests, Saturday afternoon next month)
let searchOk = false;
if (searchParams) {
  const filters = searchParams.filters || {};
  const categoryOk = searchParams.category_key === 'kids_parties';
  const locOk = (typeof searchParams.location_query === 'string' && searchParams.location_query.toLowerCase().includes('chicago')) ||
                (typeof searchParams.postal_code === 'string' && searchParams.postal_code.startsWith('606'));
  const eventTypeOk = filters.event_type === 'kids_birthday';
  const ratingOk = typeof filters.min_rating === 'number' && filters.min_rating >= 4.5 - 1e-6;
  const priceOk = typeof filters.max_price === 'number' && filters.max_price <= 250 + 1e-6;
  const durMinOk = (typeof filters.min_duration_minutes === 'number') ? filters.min_duration_minutes <= 45 : true;
  const durMaxOk = (typeof filters.max_duration_minutes === 'number') ? filters.max_duration_minutes >= 45 : true;
  const durationOk = durMinOk && durMaxOk;
  const guestOk = (typeof filters.guest_count === 'number') ? (filters.guest_count >= 10 && filters.guest_count <= 20) : true;
  const dayOk = filters.day_of_week_value === 'saturday';
  const timeOk = filters.time_of_day_value === 'afternoon';
  let dateOk = false;
  if (searchParams.event_date && baselineStr) {
    dateOk = isNextMonth(searchParams.event_date, baselineStr);
  }
  searchOk = categoryOk && locOk && eventTypeOk && ratingOk && priceOk && durationOk && guestOk && dayOk && timeOk && dateOk;
}
checkpoints.push({ passed: searchOk, weight: 0.5 });

// CP2 (0.5): There is a booking that matches the search (kids birthday, Chicago, 45 minutes, ~15 kids, Saturday afternoon next month, under $250, show rating ≥4.5) and matches the searched date
let hasQualBooking = false;
if (searchOk && baselineStr) {
  const filters = searchParams.filters || {};
  bookings.forEach(b => {
    if (b.event_type !== 'kids_birthday') return;
    if (!b.location_city || b.location_city.toLowerCase() !== 'chicago') return;
    if (!b.event_start_datetime) return;
    const datePart = b.event_start_datetime.substring(0, 10);
    if (!isNextMonth(datePart, baselineStr)) return;
    // Must be same date as searched, if provided
    if (searchParams.event_date && searchParams.event_date !== datePart) return;
    const dateOnly = new Date(datePart + 'T00:00:00Z');
    const dow = dateOnly.getUTCDay(); // 6 = Saturday
    if (dow !== 6) return;
    if (!(typeof b.guest_count === 'number' && b.guest_count >= 10 && b.guest_count <= 20)) return;
    if (!(typeof b.total_price_before_discounts === 'number' && b.total_price_before_discounts <= 250 + 1e-6)) return;
    const show = shows.find(s => s.id === b.show_id);
    if (!show || show.event_type !== 'kids_birthday') return;
    if ((show.rating_average || 0) < 4.5 - 1e-6) return;
    const pkg = showPackages.find(sp => sp.id === b.show_package_id);
    if (!pkg) return;
    const dur = b.duration_minutes || pkg.duration_minutes || 0;
    if (dur !== 45) return;
    const cats = Array.isArray(pkg.time_of_day_categories) ? pkg.time_of_day_categories : [];
    if (!cats.includes('afternoon')) return;
    hasQualBooking = true;
  });
}
checkpoints.push({ passed: hasQualBooking, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const searchParams = JSON.parse(localStorage.getItem('task2_searchParams') || 'null');
const favoritesList = JSON.parse(localStorage.getItem('favorites') || 'null');
const favoriteItems = JSON.parse(localStorage.getItem('favorite_items') || '[]');
const shows = JSON.parse(localStorage.getItem('shows') || '[]');
const showPackages = JSON.parse(localStorage.getItem('show_packages') || '[]');
const performers = JSON.parse(localStorage.getItem('performers') || '[]');

// CP1 (0.4): User searched corporate events in Seattle with stage+strolling and 2-hour filters
let searchOk = false;
if (searchParams) {
  const filters = searchParams.filters || {};
  const categoryOk = searchParams.category_key === 'corporate_events';
  const locOk = (typeof searchParams.location_query === 'string' && searchParams.location_query.toLowerCase().includes('seattle')) ||
                (typeof searchParams.postal_code === 'string' && searchParams.postal_code.startsWith('981'));
  const eventTypeOk = filters.event_type === 'corporate_event';
  const perfTypes = filters.performance_types || [];
  const perfOk = Array.isArray(perfTypes) && perfTypes.includes('stage_show') && perfTypes.includes('close_up_strolling');
  const durMinOk = (typeof filters.min_duration_minutes === 'number') ? filters.min_duration_minutes <= 120 : true;
  const durMaxOk = (typeof filters.max_duration_minutes === 'number') ? filters.max_duration_minutes >= 120 : true;
  const durationOk = durMinOk && durMaxOk;
  const ratingOk = (typeof filters.min_rating === 'number') ? filters.min_rating >= 4.0 - 1e-6 : true;
  searchOk = categoryOk && locOk && eventTypeOk && perfOk && durationOk && ratingOk;
}
checkpoints.push({ passed: searchOk, weight: 0.4 });

// CP2 (0.6): The best-value qualifying 2-hour stage+strolling corporate option under $800 and rating ≥4.0 is in favorites (either show or performer)
let hasBestValueFavorited = false;
if (searchOk && favoritesList) {
  const listItems = favoriteItems.filter(fi => fi.favorites_list_id === favoritesList.id);

  // Find 2-hour corporate shows that are stage+strolling and have a 2-hr package under $800 and rating ≥4.0
  const corporateShows = shows.filter(s => s.event_type === 'corporate_event');
  const twoHourStageStrolling = corporateShows.filter(s => {
    const types = Array.isArray(s.performance_types) ? s.performance_types : [];
    const hasBoth = types.includes('stage_show') && types.includes('close_up_strolling');
    const minD = s.duration_range_minutes_min || 0;
    const maxD = s.duration_range_minutes_max || minD;
    const durOk = minD <= 120 && maxD >= 120;
    return hasBoth && durOk;
  });

  const candidateShowInfo = [];
  twoHourStageStrolling.forEach(show => {
    const pkgs = showPackages.filter(sp => sp.show_id === show.id && sp.duration_minutes === 120);
    if (!pkgs.length) return;
    const underPkgs = pkgs.filter(sp => (sp.base_price || 0) <= 800);
    if (!underPkgs.length) return;
    const rating = show.rating_average || 0;
    if (rating < 4.0 - 1e-6) return;
    const minPrice = Math.min(...underPkgs.map(p => p.base_price || 0));
    candidateShowInfo.push({ showId: show.id, performerId: show.performer_id, minPrice });
  });

  if (candidateShowInfo.length) {
    const minPriceOverall = Math.min(...candidateShowInfo.map(c => c.minPrice));
    const bestShowIds = candidateShowInfo.filter(c => c.minPrice === minPriceOverall).map(c => c.showId);
    const bestPerformerIds = candidateShowInfo.filter(c => c.minPrice === minPriceOverall).map(c => c.performerId);

    hasBestValueFavorited = listItems.some(fi =>
      (fi.target_type === 'show' && bestShowIds.includes(fi.target_id)) ||
      (fi.target_type === 'performer' && bestPerformerIds.includes(fi.target_id))
    );
  }
}
checkpoints.push({ passed: searchOk && hasBestValueFavorited, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const customPackages = JSON.parse(localStorage.getItem('custom_packages') || '[]');
const baseShowOptions = JSON.parse(localStorage.getItem('base_show_options') || '[]');
const addonOptions = JSON.parse(localStorage.getItem('addon_options') || '[]');
const metadata = JSON.parse(localStorage.getItem('_metadata') || 'null');
const baselineStr = metadata && metadata.baselineDate ? metadata.baselineDate : null;

function isNextMonth(dateStr, baselineStr) {
  if (!dateStr || !baselineStr) return false;
  const base = new Date(baselineStr + 'T00:00:00Z');
  const d = new Date(dateStr + 'T00:00:00Z');
  let nextMonth = base.getUTCMonth() + 1;
  let nextYear = base.getUTCFullYear();
  if (nextMonth > 11) { nextMonth = 0; nextYear += 1; }
  return d.getUTCFullYear() === nextYear && d.getUTCMonth() === nextMonth;
}

let hasRequestedPkg = false;
let removedWorkshop = false;

if (baselineStr) {
  customPackages.forEach(cp => {
    if (cp.event_type !== 'kids_birthday') return;
    if (!cp.location_city || cp.location_city.toLowerCase() !== 'austin') return;
    if (cp.location_state && cp.location_state.toLowerCase() !== 'tx') return;
    if (!cp.event_date) return;
    const datePart = cp.event_date.substring(0, 10);
    if (!isNextMonth(datePart, baselineStr)) return;
    if (!(typeof cp.number_of_children === 'number' && cp.number_of_children >= 18 && cp.number_of_children <= 22)) return;
    if (!(typeof cp.total_price === 'number' && cp.total_price <= 400 + 1e-6)) return;

    const base = baseShowOptions.find(b => b.id === cp.base_show_option_id);
    if (!base) return;
    if (base.duration_minutes !== 45) return;
    if (base.base_price !== 260) return;
    if (base.event_type !== 'kids_birthday') return;

    const ids = Array.isArray(cp.add_on_option_ids) ? cp.add_on_option_ids : [];
    const addOns = addonOptions.filter(a => ids.includes(a.id));
    const hasBalloon = addOns.some(a => a.id === 'addon_balloon_twisting_30' || /balloon/i.test(a.name || ''));
    if (!hasBalloon) return;

    if (cp.status !== 'requested') return;

    hasRequestedPkg = true;

    // Check that the magic workshop add-on was not kept (so they stayed under budget)
    const hasWorkshop = ids.includes('addon_magic_workshop_30');
    if (!hasWorkshop) {
      removedWorkshop = true;
    }
  });
}

// CP1 (0.6): Requested custom package matches kids birthday in Austin next month, ~20 kids, 45-min base show, includes balloon add-on, total ≤ $400
checkpoints.push({ passed: hasRequestedPkg, weight: 0.6 });

// CP2 (0.4): Magic workshop 30-minute add-on is not in the final package, indicating it was dropped to meet budget
checkpoints.push({ passed: hasRequestedPkg && removedWorkshop, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const cart = JSON.parse(localStorage.getItem('cart') || 'null');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');
const metadata = JSON.parse(localStorage.getItem('_metadata') || 'null');
const baselineStr = metadata && metadata.baselineDate ? metadata.baselineDate : null;

let hasQualGiftCard = false;

if (cart && baselineStr) {
  const baseDate = new Date(baselineStr + 'T00:00:00Z');
  const itemsForCart = cartItems.filter(ci => ci.cart_id === cart.id && ci.item_type === 'gift_card');

  itemsForCart.forEach(ci => {
    const amount = typeof ci.gift_card_amount === 'number' ? ci.gift_card_amount : (ci.unit_price || 0);
    if (!(amount >= 125 && amount <= 175)) return;
    if (ci.gift_card_delivery_method !== 'email') return;
    if (!ci.gift_card_recipient_name || !ci.gift_card_recipient_email || !ci.gift_card_sender_name || !ci.gift_card_sender_email) return;
    if (!ci.gift_card_delivery_datetime) return;

    const datePart = ci.gift_card_delivery_datetime.substring(0, 10);
    const delDate = new Date(datePart + 'T00:00:00Z');
    const diffMs = delDate.getTime() - baseDate.getTime();
    const diffDays = diffMs / (1000 * 60 * 60 * 24);
    // Allow a small window around 14 days (about two weeks)
    if (diffDays < 12 || diffDays > 16) return;

    hasQualGiftCard = true;
  });
}

// Single checkpoint (1.0): Qualifying gift card item exists in the cart
checkpoints.push({ passed: hasQualGiftCard, weight: 1.0 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const searchParams = JSON.parse(localStorage.getItem('task5_searchParams') || 'null');
const performers = JSON.parse(localStorage.getItem('performers') || '[]');
const messages = JSON.parse(localStorage.getItem('performer_messages') || '[]');

// Helper to find cheapest qualifying performer given the task criteria
function getCheapestQualifyingPerformer() {
  const matches = performers.filter(p => {
    if (p.base_location_postal_code !== '94103') return false;
    const evts = Array.isArray(p.event_types_supported) ? p.event_types_supported : [];
    if (evts.length && !evts.includes('adult_birthday')) return false;
    const equip = Array.isArray(p.equipment_provided) ? p.equipment_provided : [];
    const hasSound = !!p.provides_sound_system || equip.includes('sound_system');
    if (!hasSound) return false;
    return true;
  });
  if (!matches.length) return null;
  matches.sort((a, b) => (a.min_price || 0) - (b.min_price || 0));
  return matches[0] || null;
}

// CP1 (0.4): User searched performers in 94103 with sound system filter, adult birthday event, and price low-to-high sort
let searchOk = false;
if (searchParams) {
  const filters = searchParams.filters || {};
  const categoryOk = searchParams.category_key === 'all_performers';
  const zipOk = searchParams.postal_code === '94103';
  const radiusOk = typeof searchParams.radius_miles === 'number' ? (searchParams.radius_miles >= 5 && searchParams.radius_miles <= 15) : false;
  const eventTypeOk = filters.event_type === 'adult_birthday';
  const equipVals = filters.equipment_values || [];
  const equipOk = Array.isArray(equipVals) && equipVals.includes('sound_system');
  const sortOk = searchParams.sort_key === 'total_price_asc';
  searchOk = categoryOk && zipOk && radiusOk && eventTypeOk && equipOk && sortOk;
}
checkpoints.push({ passed: searchOk, weight: 0.4 });

// CP2 (0.6): Message sent to the cheapest qualifying performer, about an August date, mentioning a short card-trick lesson
let hasQualMessage = false;
const cheapestPerf = getCheapestQualifyingPerformer();

if (searchOk && cheapestPerf) {
  messages.forEach(m => {
    if (m.performer_id !== cheapestPerf.id) return;
    if (!m.sender_name || !m.sender_email) return;
    if (m.event_type && m.event_type !== 'adult_birthday') return;
    if (!m.message_body) return;
    const body = m.message_body.toLowerCase();
    if (!/august/i.test(m.message_body)) return;
    if (!(body.includes('card') && body.includes('lesson'))) return;
    if (!m.event_date) return;
    const datePart = m.event_date.substring(0, 10);
    const d = new Date(datePart + 'T00:00:00Z');
    if (isNaN(d.getTime())) return;
    if (d.getUTCMonth() !== 7) return; // August is month index 7
    hasQualMessage = true;
  });
}

checkpoints.push({ passed: hasQualMessage, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const searchParams = JSON.parse(localStorage.getItem('task6_searchParams') || 'null');
const shows = JSON.parse(localStorage.getItem('shows') || '[]');
const quoteRequests = JSON.parse(localStorage.getItem('quote_requests') || '[]');

// CP1 (0.4): User searched shows catalog with age 5–7, no live animals, 30–45 minute duration
let searchOk = false;
if (searchParams) {
  const filters = searchParams.filters || {};
  const categoryOk = searchParams.category_key === 'browse_shows';
  const ageOk = filters.age_group === 'ages_5_7';
  const animalsOk = filters.requires_no_live_animals === true;
  const durMinOk = (typeof filters.min_duration_minutes === 'number') ? filters.min_duration_minutes <= 30 : true;
  const durMaxOk = (typeof filters.max_duration_minutes === 'number') ? (filters.max_duration_minutes >= 40 && filters.max_duration_minutes <= 45) : true;
  const durationOk = durMinOk && durMaxOk;
  searchOk = categoryOk && ageOk && animalsOk && durationOk;
}
checkpoints.push({ passed: searchOk, weight: 0.4 });

// Identify qualifying interactive no-animal shows for ages 5–7 and 30–45 minutes
const candidateShowIds = shows.filter(s => {
  const ageGroups = Array.isArray(s.age_groups) ? s.age_groups : [];
  const ageOk = ageGroups.includes('ages_5_7') || s.primary_age_group === 'ages_5_7';
  const animalsOk = !s.includes_live_animals;
  const interactiveOk = s.is_interactive === true;
  const minD = s.duration_range_minutes_min || 0;
  const maxD = s.duration_range_minutes_max || minD;
  const durationOk = minD >= 30 && maxD <= 45;
  return ageOk && animalsOk && interactiveOk && durationOk;
}).map(s => s.id);

// CP2 (0.6): Quote request for a qualifying show, school_show event, ~25 kids, at 10:00 AM
let hasQualQuote = false;

if (searchOk && candidateShowIds.length) {
  quoteRequests.forEach(q => {
    if (!candidateShowIds.includes(q.show_id)) return;
    if (q.event_type && q.event_type !== 'school_show') return;
    if (!(typeof q.number_of_children === 'number' && q.number_of_children >= 20 && q.number_of_children <= 30)) return;
    const time = (q.preferred_start_time || '').trim().toLowerCase();
    const timeOk = time === '10:00 am' || time === '10:00' || time === '10am' || time === '10 am';
    if (!timeOk) return;
    if (!q.requester_name || !q.requester_email) return;
    hasQualQuote = true;
  });
}

checkpoints.push({ passed: hasQualQuote, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const bookings = JSON.parse(localStorage.getItem('bookings') || '[]');
const shows = JSON.parse(localStorage.getItem('shows') || '[]');
const showPackages = JSON.parse(localStorage.getItem('show_packages') || '[]');

function getDayOfWeekIndex(dateStr) {
  const d = new Date(dateStr + 'T00:00:00Z');
  return d.getUTCDay(); // 0=Sun,1=Mon,...
}

function computeTotalsAfterWeekday20(booking, pkg) {
  if (!pkg) return null;
  const base = pkg.base_price || 0;
  const maxIncl = pkg.max_guests_included || 0;
  const extraPrice = pkg.additional_guest_price || 0;
  const guests = booking.guest_count || 0;
  let additional = 0;
  if (maxIncl > 0 && guests > maxIncl) {
    additional = (guests - maxIncl) * extraPrice;
  }
  const baseTotal = base + additional;
  const totalAfter = baseTotal * 0.8; // 20% off
  return { baseTotal, totalAfter };
}

let hasBestBooking = false;

bookings.forEach(b => {
  const show = shows.find(s => s.id === b.show_id);
  const pkg = showPackages.find(sp => sp.id === b.show_package_id);
  if (!show || !pkg) return;

  // Must be a corporate close-up 1-hour weekday afternoon booking with WEEKDAY20 applied and total <= 300
  if (show.event_type !== 'corporate_event') return;
  const types = Array.isArray(show.performance_types) ? show.performance_types : (show.primary_performance_type ? [show.primary_performance_type] : []);
  if (!types.includes('close_up_strolling')) return;
  const dur = b.duration_minutes || pkg.duration_minutes || 0;
  if (dur !== 60) return;
  if (!b.event_start_datetime) return;
  const datePart = b.event_start_datetime.substring(0, 10);
  const dow = getDayOfWeekIndex(datePart);
  if (dow < 1 || dow > 4) return; // Not Monday–Thursday
  const cats = Array.isArray(pkg.time_of_day_categories) ? pkg.time_of_day_categories : [];
  if (!cats.includes('afternoon')) return;
  if (b.promo_code_code !== 'WEEKDAY20') return;
  if (typeof b.total_price_after_discounts !== 'number' || b.total_price_after_discounts > 300 + 1e-6) return;

  // Enforce that the chosen package is the best-value similar 1-hour option under $300 after promo
  const siblingPkgs = showPackages.filter(sp => sp.show_id === show.id && sp.is_active !== false);
  const similarPkgs = siblingPkgs.filter(sp => Math.abs((sp.duration_minutes || 0) - dur) <= 30);

  const totals = similarPkgs.map(sp => {
    const calc = computeTotalsAfterWeekday20(b, sp);
    return { pkgId: sp.id, totalAfter: calc.totalAfter };
  });

  const underCap = totals.filter(t => t.totalAfter <= 300 + 1e-6);
  if (!underCap.length) return;
  const minTotal = Math.min(...underCap.map(t => t.totalAfter));
  const bestPkgIds = underCap.filter(t => t.totalAfter === minTotal).map(t => t.pkgId);

  if (bestPkgIds.includes(b.show_package_id)) {
    hasBestBooking = true;
  }
});

// Single checkpoint (1.0): A qualifying booking exists that uses the best-value suggested 1-hour close-up package under $300 after WEEKDAY20
checkpoints.push({ passed: hasBestBooking, weight: 1.0 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const bookings = JSON.parse(localStorage.getItem('bookings') || '[]');

let hasRescheduledKidsSunday = false;

bookings.forEach(b => {
  if (b.event_type !== 'kids_birthday') return;
  if (b.status !== 'rescheduled') return;
  if (!b.event_start_datetime) return;
  const datePart = b.event_start_datetime.substring(0, 10);
  const d = new Date(datePart + 'T00:00:00Z');
  if (d.getUTCDay() !== 0) return; // Sunday
  hasRescheduledKidsSunday = true;
});

// Single checkpoint (1.0): A kids birthday booking has been rescheduled to a Sunday (within-30-days and same-time are enforced by BusinessLogic.rescheduleBooking)
checkpoints.push({ passed: hasRescheduledKidsSunday, weight: 1.0 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
